#include <stdio.h>
#include <stdbool.h>

#define MEMORY_SIZE 1000

typedef struct {
    int process_id;
    int size;
    int start;
    bool allocated;
} Partition;

void initialize_memory(Partition partitions[], int *num_partitions) {
    partitions[0].process_id = -1;
    partitions[0].size = MEMORY_SIZE;
    partitions[0].start = 0;
    partitions[0].allocated = false;
    *num_partitions = 1;
}

void first_fit(Partition partitions[], int num_partitions, int pid, int size) {
    for (int i = 0; i < num_partitions; i++) {
        if (!partitions[i].allocated && partitions[i].size >= size) {
            // Split partition
            Partition new_partition;
            new_partition.process_id = -1;
            new_partition.size = partitions[i].size - size;
            new_partition.start = partitions[i].start + size;
            new_partition.allocated = false;

            partitions[i].process_id = pid;
            partitions[i].size = size;
            partitions[i].allocated = true;

            // Insert new partition
            for (int j = num_partitions; j > i; j--) {
                partitions[j] = partitions[j-1];
            }
            partitions[i+1] = new_partition;
            printf("Process %d allocated at address %d, size %d\n", 
                   pid, partitions[i].start, size);
            return;
        }
    }
    printf("Cannot allocate - no suitable partition found\n");
}

void deallocate(Partition partitions[], int num_partitions, int pid) {
    for (int i = 0; i < num_partitions; i++) {
        if (partitions[i].process_id == pid && partitions[i].allocated) {
            partitions[i].allocated = false;
            partitions[i].process_id = -1;
            printf("Process %d deallocated\n", pid);
            return;
        }
    }
}
